const CACHE_VERSION="tokobangunan-__BUILD_SHA__",PRECACHE_URLS=["/login","/dashboard","/penjualan/baru","/static/css/app.css","/static/js/htmx.min.js","/static/js/alpine.min.js","/static/js/app.js","/static/js/sync.js","/static/js/uuid.js","/static/js/penjualan-offline.js","/static/js/sw-register.js","/static/manifest.webmanifest"],STATIC_EXT=/\.(?:css|js|woff2?|ttf|otf|eot|png|jpg|jpeg|gif|svg|ico|webp|webmanifest)$/i,DB_NAME="tokobangunan-sync",DB_VERSION=1,STORE_NAME="pending";function openDB(){return new Promise((t,s)=>{const e=indexedDB.open(DB_NAME,1);e.onupgradeneeded=()=>{const n=e.result;n.objectStoreNames.contains(STORE_NAME)||n.createObjectStore(STORE_NAME,{keyPath:"id",autoIncrement:!0})},e.onsuccess=()=>t(e.result),e.onerror=()=>s(e.error)})}async function enqueueRequest(t){const s=await openDB();return new Promise((e,n)=>{const c=s.transaction(STORE_NAME,"readwrite").objectStore(STORE_NAME).add(t);c.onsuccess=()=>e(c.result),c.onerror=()=>n(c.error)})}self.addEventListener("install",t=>{t.waitUntil(caches.open(CACHE_VERSION).then(s=>Promise.all(PRECACHE_URLS.map(e=>s.add(new Request(e,{credentials:"same-origin"})).catch(()=>{}))))),self.skipWaiting()}),self.addEventListener("activate",t=>{t.waitUntil(caches.keys().then(s=>Promise.all(s.filter(e=>e!==CACHE_VERSION).map(e=>caches.delete(e))))),self.clients.claim()}),self.addEventListener("fetch",t=>{const s=t.request,e=new URL(s.url);if(e.origin===self.location.origin){if(s.method==="POST"&&e.pathname==="/penjualan"){t.respondWith(handlePenjualanPost(s));return}if(s.method==="GET"){if(STATIC_EXT.test(e.pathname)||e.pathname.startsWith("/static/")){/\.(?:js|css)$/.test(e.pathname)?t.respondWith(staleWhileRevalidate(s)):t.respondWith(cacheFirst(s));return}t.respondWith(networkFirst(s))}}});async function staleWhileRevalidate(t){const s=await caches.open(CACHE_VERSION),e=await s.match(t),n=fetch(t).then(a=>(a&&a.ok&&s.put(t,a.clone()),a)).catch(()=>e);return e||n}async function cacheFirst(t){const s=await caches.match(t);if(s)return s;try{const e=await fetch(t);return e&&e.ok&&(await caches.open(CACHE_VERSION)).put(t,e.clone()),e}catch{return new Response("Offline",{status:503,statusText:"Offline"})}}async function networkFirst(t){try{const s=await fetch(t);return s&&s.ok&&t.method==="GET"&&(await caches.open(CACHE_VERSION)).put(t,s.clone()),s}catch{const e=await caches.match(t);if(e)return e;if(t.mode==="navigate"){const n=await caches.match("/dashboard");if(n)return n}return new Response("Offline",{status:503,statusText:"Offline",headers:{"Content-Type":"text/plain; charset=utf-8"}})}}async function handlePenjualanPost(t){try{const s=t.clone();return await fetch(t)}catch{let e="",n=t.headers.get("Content-Type")||"";try{e=await t.clone().text()}catch{e=""}const a={};t.headers.forEach((i,r)=>{a[r]=i});let o="";try{n.includes("application/x-www-form-urlencoded")?o=new URLSearchParams(e).get("client_uuid")||"":n.includes("application/json")&&(o=JSON.parse(e).client_uuid||"")}catch{}await enqueueRequest({url:t.url,method:t.method,headers:a,body:e,contentType:n,client_uuid:o,created_at:Date.now()});try{self.registration&&self.registration.sync&&await self.registration.sync.register("sync-queue")}catch{}const c=JSON.stringify({ok:!0,queued:!0,client_uuid:o,message:"Tersimpan offline, akan sync saat online"});return new Response(c,{status:202,statusText:"Accepted (Queued Offline)",headers:{"Content-Type":"application/json; charset=utf-8"}})}}self.addEventListener("message",t=>{const s=t.data||{};s.type==="SKIP_WAITING"?self.skipWaiting():s.type==="FLUSH_QUEUE"&&t.waitUntil(notifyClientsToFlush())});async function notifyClientsToFlush(){const t=await self.clients.matchAll({includeUncontrolled:!0});for(const s of t)s.postMessage({type:"SYNC_FLUSH_REQUEST"})}self.addEventListener("sync",t=>{t.tag==="sync-queue"&&t.waitUntil(notifyClientsToFlush())});
